import React, { useState } from 'react';
import summerImg from '../assets/images/sumer discount.png';
import avatar1 from '../assets/images/i1.png';
import avatar2 from '../assets/images/i2.png';
import avatar3 from '../assets/images/i3.png';
import './TestimonialServices.css';

const testimonials = [
  { id: 1, img: avatar1, name: 'ALAN DOE',    role: 'CEO & Founder Invision',  text: 'Lorem ipsum dolor sit amet consectetur Lorem ipsum dolor dolor sit amet.' },
  { id: 2, img: avatar2, name: 'JANE SMITH',  role: 'Marketing Director',       text: 'Lorem ipsum dolor sit amet consectetur Lorem ipsum dolor dolor sit amet.' },
  { id: 3, img: avatar3, name: 'MIKE JONES',  role: 'Product Manager',          text: 'Lorem ipsum dolor sit amet consectetur Lorem ipsum dolor dolor sit amet.' },
];

const services = [
  { icon: '🚢', title: 'Worldwide Delivery',   sub: 'For Order Over $100'  },
  { icon: '🚀', title: 'Next Day Delivery',    sub: 'UK Orders Only'       },
  { icon: '📞', title: 'Best Online Support',  sub: 'Hours: 8AM – 11PM'   },
  { icon: '🔄', title: 'Return Policy',        sub: 'Easy & Free Return'   },
  { icon: '💰', title: '30% Money Back',       sub: 'For Order Over $100'  },
];

export default function TestimonialServices() {
  const [current, setCurrent] = useState(0);
  const t = testimonials[current];

  return (
    <section className="ts-section">

      {/* ── Left: Testimonial ── */}
      <div className="ts-left">
        <h2 className="ts-heading">Testimonial</h2>
        <div className="ts-card">
          <div className="ts-avatar">
            <div className="ts-avatar-circle">
              <img src={t.img} alt={t.name} className="ts-avatar-img" />
            </div>
          </div>
          <p className="ts-name">{t.name}</p>
          <p className="ts-role">{t.role}</p>
          <div className="ts-quote-icon">"</div>
          <p className="ts-text">{t.text}</p>
          <div className="ts-dots">
            {testimonials.map((_, i) => (
              <button
                key={i}
                className={`ts-dot ${i === current ? 'active' : ''}`}
                onClick={() => setCurrent(i)}
              />
            ))}
          </div>
        </div>
      </div>

      {/* ── Center: Summer Banner ── */}
      <div className="ts-center">
        <img src={summerImg} alt="Summer Collection" className="ts-banner-img" />
      </div>

      {/* ── Right: Our Services ── */}
      <div className="ts-right">
        <h2 className="ts-heading">Our Services</h2>
        <div className="ts-services">
          {services.map((s, i) => (
            <div className="ts-service-item" key={i}>
              <span className="ts-service-icon">{s.icon}</span>
              <div className="ts-service-info">
                <p className="ts-service-title">{s.title}</p>
                <p className="ts-service-sub">{s.sub}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

    </section>
  );
}
